  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
`;

const Profile = () => {
  return (
    <Container>
      <h1>Profile</h1>
      <p>About section with YAML-style content.</p>
    </Container>
  );
};

export default Profile;

import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';

const App = () => {
  return (
    <Router>
      <Switch>
        <Route path="/profile" exact component={Profile} />
      </Switch>
    </Router>
  );
};

export default App;

