import { createStore } from 'redux';

const initialState = {
  profile: {}
};

const reducer = (state = initialState, action) => {
  switch (action.type) {
    case 'SET_PROFILE':
      return { ...state, profile: action.payload };
    default:
      return state;
  }
};

const store = createStore(reducer);

store.dispatch({ type: 'SET_PROFILE', payload: { name: 'John Doe', about: 'AI & Automation Engineer' } });

import React from 'react';
import { render, screen } from '@testing-library/react';
import Profile from './Profile';

describe('Profile component', () => {
  test('renders profile name and about section', () => {
    render(<Profile name="John Doe" about="AI & Automation Engineer" />);
    expect(screen.getByText('John Doe')).toBeInTheDocument();
    expect(screen.getByText('AI & Automation Engineer')).toBeInTheDocument();
  });
});

